Not to be confused with #8, the idea here is that users will have custom objects (good example is `datetime.datetime`) that they'd prefer not to have to serialize before an emit call and automatically deserialized so that logic doesn't complicate their Bolts/Spouts.  Both simplejson and the Python stdlib json packages support this.

Recommend that we allow users to register callback functions for json encoding / decoding and add to the IPC module when reading from stdin / writing to stdout.

Perhaps something like a mixin model, if a `_to_json` or `_from_json` method is defined on the component, it's used:

```python
import base64
import datetime as dt
import random

from streamparse.bolt import Bolt
from streamparse.spout import Spout
import numpy as np
import simplejson as json


class CustomJSONSerializerMixin(object):

    _UNIX_EPOCH = dt.datetime.utcfromtimestamp(0)

    def json_default(self, obj):
        if isinstance(obj, complex):
            return {'__t': 'complex', 'r': obj.real, 'i': obj.imag}
        elif isinstance(obj, dt.datetime):
            # assumes datetime is UTC
            return {'__t': 'datetime', 'v': int((obj - self._UNIX_EPOCH).total_seconds() * 1000)}
        elif isinstance(obj, np.ndarray):
            data_b64 = base64.b64encode(obj.data)
            return {'__t': 'ndarray', 'v': data_b64, 't': str(obj.dtype), 's': obj.shape}

        raise TypeError('%r is not JSON serializable.' % obj)

    def json_object_hook(self, obj):
        obj_type = obj.get('__t')
        if obj_type == 'complex':
            return complex(obj['r'], obj['i'])
        if obj_type == 'datetime':
            return dt.datetime.utcfromtimestamp(obj['v'] / 1000.0)
        if obj_type == 'ndarray':
            data = base64.b64decode(obj['v'])
            dtype = obj['t']
            shape = obj['s']
            return np.frombuffer(data, dtype).reshape(shape)
        return obj


"""Override send_message calls in Bolt and Spout so that it does something
like:

    default_fn = getattr(self, 'json_default', None)
    send_message(msg, default=default_fn)

And similar for read_command:

    object_hook_fn = getattr(self, 'json_object_hook', None)
    read_command(object_hook=object_hook_fn)
"""

class ComplexSpout(Spout, CustomJSONSerializerMixin):

    def next_tuple(self):
        real = random.randint(1, 100)
        imag = random.randint(1, 100)
        self.emit([complex(real, imag)])


class ComplexAdder(Bolt, CustomJSONSerializerMixin):

    def process(self, tup):
        complex_a, complex_b = tup.values
        self.emit([complex_a + complex_b])


if __name__ == '__main__':
    obj = {
        'dt': dt.datetime.utcnow(),
        'complex': complex(10, 5),
        'np': np.arange(100, dtype=np.float)
    }
    serializer = CustomJSONSerializerMixin()
    res = json.dumps(obj, default=serializer._json_default)
    print res
    print json.loads(res, object_hook=serializer._json_object_hook)

```

We'd then tweak the `ipc.send_message` and `ipc.read_command` functions to take the optional callback function.

