    def method1(self, a, b):
        """

        :param a:
        :param b:
        :return:
        """
        return a+b


@implementer(MyInterface)
class MySecondImplementation:

    def method1(self, a: int, b: str) -> str:
        """

        :param a:
        :param b:
        :return:
        """
        return "%s %s" % (a, b)

