(declare-const Counterpp Int)
(declare-const PCpp Int)


(compute-interpolant
   (and (and Init P0) 
     (= Init (and (= Counter 0) (= PC 0)))
     (= P0 (< Counter 4))
     (=> (= PC 0)
       (and (= Counter3 (+ Counter 1))
         (>= (+ Counter 1) (- 32768))
         (< (+ Counter 1) 32768)
         (= Counter4 (mod Counter3 5))
         (= Counter4 Counter1)
         (= Counterp Counter4)
         (= PCp 0)
       )
     )
   )
   (and (and (not Initpp) (not P0pp)) 
